fun process(a: Int, b: Int): String {
    var result = ""
    if (a > 0) result += "a"
    if (b > 0) result += "b"
    return result
}

fun outer(a: Int): String {
    fun inner(b: Int, c: Int): String {
        var result = ""
        if (b > 0) result += "b"
        if (c > 0) result += "c"
        return result
    }
    return if (a > 0) inner(a, a) else ""
}

fun describe(n: Int): String = when {
    n < 0    -> "negative"
    n == 0   -> "zero"
    n < 100  -> "small"
    else     -> "large"
}

fun isValid(a: Int, b: Int, c: Int, d: Int): Boolean {
    return a > 0 && b > 0 && c > 0 && d > 0
}

fun resolve(a: String?, b: String?, c: String?): String {
    return a ?: b ?: c ?: "default"
}
